:"spark.sql(\"SELECT * FROM loans_delta LIMIT 5\").show()","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"2f153d58-ae5e-46e9-b036-a26b4fcc8c2b"},{"version":"CommandV1","origId":1083584440950210,"guid":"51450d22-b943-490a-8aa1-ecd615ff1f36","subtype":"command","commandType":"auto","position":7.0,"command":"%md\n## ![Delta Lake Tiny Logo](https://pages.databricks.com/rs/094-YMS-629/images/delta-lake-tiny-logo.png) Loading data streams into Delta Lake table\n\nWe will generate a stream of data from with randomly generated loan ids and amounts. \nIn addition, we are going to define a few useful utility functions.","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"65458364-655a-48f2-9b6a-11cb3be62baa"},{"version":"CommandV1","origId":1083584440950211,"guid":"e3ea26fd-831f-4360-9a7c-d138ff1443f4","subtype":"command","commandType":"auto","position":8.0,"command":"import java.util.Random\nimport org.apache.spark.sql.functions._\nimport org.apache.spark.sql.streaming.{StreamingQuery, Trigger}\nimport org.apache.spark.sql.types._\n\nval random = new Random()\n\ndef randomCheckpointDir: String = \n  s\"/tmp/chkpt/${random.nextInt(10000)}\"\n\n\n// User-defined function to generate random state\nval states = Seq(\"CA\", \"TX\", \"NY\", \"WA\")\nval randomState = udf(() => states(random.nextInt(states.length)))\n\n// Function to start a streaming query with a stream of randomly generated data and append to the parquet table\ndef generateAndAppendDataStream(): StreamingQuery = {\n  \n  val newLoanStreamDF = spark.readStream.format(\"rate\").option(\"rowsPerSecond\", 5).load()\n    .withColumn(\"loan_id\", col(\"value\") + 10000)\n    .withColumn(\"funded_amnt\", (rand() * 5000 + 5000).cast(\"integer\"))\n    .withColumn(\"paid_amnt\", col(\"funded_amnt\") - (rand() * 2000))\n    .withColumn(\"addr_state\", randomState())\n    .select(\"loan_id\", \"funded_amnt\", \"paid_amnt\", \"addr_state\")\n\n  val streamingQuery = newLoanStreamDF.writeStream\n    .format(\"delta\")\n    .option(\"checkpointLocation\", randomCheckpointDir)\n    .trigger(Trigger.ProcessingTime(\"10 seconds\"))\n    .start(deltaPath)\n\n  streamingQuery\n}\n\n// Function to stop all streaming queries \ndef stopAllStreams(): Unit = {\n  // Stop all the streams\n  println(\"Stopping all streams\")\n  spark.streams.active.foreach(_.stop())\n  println(\"Stopped all streams\")\n  println(\"Deleting checkpoints\")  \n  dbutils.fs.rm(\"/tmp/chkpt/\", true)\n  println(\"Deleted checkpoints\")\n}","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"23cb34ca-6b17-4326-8014-554b3d70e015"},{"version":"CommandV1","origId":1083584440950212,"guid":"d862c862-cdc1-4616-9baa-fccd59d66774","subtype":"command","commandType":"auto","position":9.0,"command":"val streamQuery = generateAndAppendDataStream() ","commandVersion":0,"state":"finished","results":null,"errorSummary":null,"errorTraceType":null,"error":null,"workflows":[],"startTime":0,"submitTime":0,"finishTime":0,"collapsed":false,"bindings":{},"inputWidgets":{},"displayType":"table","width":"auto","height":"auto","xColumns":null,"yColumns":null,"pivotColumns":null,"pivotAggregation":null,"useConsistentColors":false,"customPlotOptions":{},"commentThread":[],"commentsVisible":false,"parentHierarchy":[],"diffInserts":[],"diffDeletes":[],"globalVars":{},"latestUser":"a user","latestUserId":null,"commandTitle":"","showCommandTitle":false,"hideCommandCode":false,"hideCommandResult":false,"isLockedInExamMode":false,"iPythonMetadata":null,"streamStates":{},"datasetPreviewNameToCmdIdMap":{},"tableResultSubCmdIds":[],"tableResultIndex":null,"nuid":"53fdcd00-a48c-4c8d-9d14-44abea092fa9"},{"version":"CommandV1","origId":1083584440950213,"guid":"88201908-2ba2-4705-a5a7-0abc6470798f",